import{_ as s,c as e,a as n,o as i}from"./app-CEcM0piI.js";const l={};function p(d,a){return i(),e("div",null,a[0]||(a[0]=[n(`<p>大部分程序都需要这个框架</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#include &lt;stdio.h&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>int main(){</span></span>
<span class="line"><span>	return 0;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="头文件" tabindex="-1"><a class="header-anchor" href="#头文件"><span>头文件</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#include &lt;stdio.h&gt;</span></span>
<span class="line"><span>#include &quot;Pink.h&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>程序中有时需要调用标准库或其他库函数，这些库函数编译器是不认识的，程序中调用库函数之前需要包含头文件，在这个头函数中有相应库函数的声明 stdio.h是标准库，包含c语言中的内置函数，需要包含该库，编辑器本身不具有标准库。</p><p>导入自己写的文件是要用双引号引用 用尖括号包含头文件，在系统指定的路径下找头文件。 用双引号包含头文件，先在当前目录下找头文件，找不到再到系统指定的路径下找。 故尖括号只能引用标准库，双引号既能引用标准库又能引用自己写的文件</p><p>头文件相当于python中的import stdio</p><p>一般.c写程序，.h声明函数</p><h2 id="main函数" tabindex="-1"><a class="header-anchor" href="#main函数"><span>main函数</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int main()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>主函数，程序都是从main开始执行的是程序的入口，在一个程序中有且只有一个main函数 一般返回整形，故前面要有int 对应return 0;</p><h2 id="语句结尾" tabindex="-1"><a class="header-anchor" href="#语句结尾"><span>语句结尾</span></a></h2><p>c语言中每条语句都要用;结尾</p><h1 id="注释" tabindex="-1"><a class="header-anchor" href="#注释"><span>注释</span></a></h1><p>//在一行中注释 /* 注释所有中间的内容*/ 选中ctrl+/ 一键注释</p><h1 id="编译过程" tabindex="-1"><a class="header-anchor" href="#编译过程"><span>编译过程</span></a></h1><h3 id="_1-预编译" tabindex="-1"><a class="header-anchor" href="#_1-预编译"><span>1: 预编译</span></a></h3><p>将.c 中的头文件展开、宏展开生成的文件是.i 文件</p><h3 id="_2-编译" tabindex="-1"><a class="header-anchor" href="#_2-编译"><span>2: 编译</span></a></h3><p>将预处理之后的.i 文件生成s 汇编文件 汇编语言</p><h3 id="_3、汇编" tabindex="-1"><a class="header-anchor" href="#_3、汇编"><span>3、汇编</span></a></h3><p>将.s 汇编文件生成.o目标文件 二进制文件</p><h3 id="_4、链接" tabindex="-1"><a class="header-anchor" href="#_4、链接"><span>4、链接</span></a></h3><p>将所有.o文件链接成目标文件</p><h1 id="静态库" tabindex="-1"><a class="header-anchor" href="#静态库"><span>静态库</span></a></h1><h2 id="_1、动态编译" tabindex="-1"><a class="header-anchor" href="#_1、动态编译"><span>1、动态编译</span></a></h2><p>动态编译使用的是动态库文件进行编译 gcc hello.c -o hello默认的咱们使用的是动态编译方法</p><h2 id="_2、静态编译" tabindex="-1"><a class="header-anchor" href="#_2、静态编译"><span>2、静态编译</span></a></h2><p>静态编译使用的静态库文件进行编译 gcc -static hello.c -o hello</p><h2 id="三-静态编译和动态编译区别" tabindex="-1"><a class="header-anchor" href="#三-静态编译和动态编译区别"><span>三:静态编译和动态编译区别</span></a></h2><h3 id="_1-使用的库文件的格式不一样" tabindex="-1"><a class="header-anchor" href="#_1-使用的库文件的格式不一样"><span>1:使用的库文件的格式不一样</span></a></h3><p>动态编译使用动态库，静态编译使用静态库</p><p>静态编译要把静态库文件打包编译到可执行程序中。 动态编译不会把动态库文件打包编译到可执行程序中，它只是编译链接关系</p><h2 id="制作静态库" tabindex="-1"><a class="header-anchor" href="#制作静态库"><span>制作静态库:</span></a></h2><p>gcc -c mylib.c -o mylib.o ar rc libtestlib.a mylib.o 注意: 静态库起名的时候必须以 lib 开头以a 结尾</p><h2 id="编译程序" tabindex="-1"><a class="header-anchor" href="#编译程序"><span>编译程序:</span></a></h2><h3 id="方法1" tabindex="-1"><a class="header-anchor" href="#方法1"><span>方法1:</span></a></h3><p>gcc -static mytest.c libtestlib.a -o mytest</p><h3 id="方法-2" tabindex="-1"><a class="header-anchor" href="#方法-2"><span>方法 2:</span></a></h3><p>指定头文件及库文件的路径</p><p>将 libtestlib.a mylib.h 移动到/home/edu 下 mv libtestlib.a mylib.h /home/edu</p><p>编译程序命令: gcc -static mytest.c -o mytest -L/home/edu -ltestlib -I/home/edu 注意: -L 是指定库文件的路径 -l指定找哪个库，指定的只要库文件名 lib 后面a 前面的部分 -I指定头文件的路径</p><h2 id="方法-3" tabindex="-1"><a class="header-anchor" href="#方法-3"><span>方法 3:</span></a></h2><p>将库文件及头文件存放到系统默认指定的路径下 库文件默认路径是 /lib 或者是/usr/lib 头文件默认路径是/usr/include sudo mv libtestlib.a /usr/lib sudo mv mylibh /usr/include</p><p>编译程序的命令 gcc -static mytest.c -o mytest -ltestlib</p><h1 id="制作动态链接库" tabindex="-1"><a class="header-anchor" href="#制作动态链接库"><span>制作动态链接库:</span></a></h1><p>gcc -shared mylib.c -o libtestlib.so //使用 gcc 编译、制作动态链接库</p><h2 id="动态链接库的使用" tabindex="-1"><a class="header-anchor" href="#动态链接库的使用"><span>动态链接库的使用:</span></a></h2><h3 id="方法-1-库函数、头文件均在当前目录下" tabindex="-1"><a class="header-anchor" href="#方法-1-库函数、头文件均在当前目录下"><span>方法 1:库函数、头文件均在当前目录下</span></a></h3><p>gcc mytest.c libtestlib.so -o mytest export LD_LIBRARY_PATH=/:SLD LIBRARY_PATH ./mytest</p><h3 id="方法2-库函数、头文件假设在-opt-目录" tabindex="-1"><a class="header-anchor" href="#方法2-库函数、头文件假设在-opt-目录"><span>方法2: 库函数、头文件假设在/opt 目录</span></a></h3><p>gcc mytest.c -o mytest -L/home/teacher-ltestlib -I/home/teacher 编译通过，运行时出错，编译时找到了库函数，但链接时找不到库，执行以下操作，把当前目录加入搜索路径 export LD_LIBRARY_PATH=.:SLD_LIBRARY_PATH #./mytest 可找到动态链接库</p><h3 id="方法-3-库函数、头文件假设在-home-edu-目录" tabindex="-1"><a class="header-anchor" href="#方法-3-库函数、头文件假设在-home-edu-目录"><span>方法 3:库函数、头文件假设在/home/edu.目录</span></a></h3><p>gcc mytest.c -o mytest -L/home/edu -ltestlib -I/home/edu</p><p>编译通过，运行时出错，编译时找到了库函数，但链接时找不到库，执行以下操作，把当前目录加入搜索路径</p><h1 id="内存分区" tabindex="-1"><a class="header-anchor" href="#内存分区"><span>内存分区</span></a></h1><h2 id="物理内存、虚拟内存物理内存-实实在在存在的存储设备" tabindex="-1"><a class="header-anchor" href="#物理内存、虚拟内存物理内存-实实在在存在的存储设备"><span>物理内存、虚拟内存物理内存:实实在在存在的存储设备</span></a></h2><p>虚拟内存:操作系统虚拟出来的内存。 操作系统会在物理内存和虚拟内存之间做映射</p><h2 id="虚拟内存" tabindex="-1"><a class="header-anchor" href="#虚拟内存"><span>虚拟内存</span></a></h2><h3 id="在运行程序的时候-操作系统会将-虚拟内存进行分区。" tabindex="-1"><a class="header-anchor" href="#在运行程序的时候-操作系统会将-虚拟内存进行分区。"><span>在运行程序的时候，操作系统会将 虚拟内存进行分区。</span></a></h3><h5 id="_1、堆" tabindex="-1"><a class="header-anchor" href="#_1、堆"><span>1、堆</span></a></h5><p>在动态申请内存的时候，在堆里开辟内存。</p><h5 id="_2、栈" tabindex="-1"><a class="header-anchor" href="#_2、栈"><span>2、栈</span></a></h5><p>主要存放局部变量。</p><h5 id="_3、静态全局区" tabindex="-1"><a class="header-anchor" href="#_3、静态全局区"><span>3、静态全局区</span></a></h5><p>a、未初始化的静态全局区静态变量(定义变量的时候，前面加 static 修饰)，或全局变量 ，没有初始化的，存在此区 b、初始化的静态全局区全局变量、静态变量，赋过初值的，存放在此区</p><h5 id="_4、代码区" tabindex="-1"><a class="header-anchor" href="#_4、代码区"><span>4、代码区</span></a></h5><p>存放程序代码</p><h5 id="_5、文字常量区" tabindex="-1"><a class="header-anchor" href="#_5、文字常量区"><span>5、文字常量区</span></a></h5><p>存放常量。</p><h1 id="内存动态申请" tabindex="-1"><a class="header-anchor" href="#内存动态申请"><span>内存动态申请</span></a></h1><h3 id="静态分配" tabindex="-1"><a class="header-anchor" href="#静态分配"><span>静态分配</span></a></h3><p>1、在程序编译或运行过程中，按事先规定大小分配内存空间的分配方式。int a[10] 2、必须事先知道所需空间的大小。 3、分配在栈区或全局变量区，一般以数组的形式。 4、按计划分配。</p><h3 id="动态分配" tabindex="-1"><a class="header-anchor" href="#动态分配"><span>动态分配</span></a></h3><p>1、在程序运行过程中，根据需要大小自由分配所需空间。 2、按需分配。 3、分配在堆区，一般使用特定的函数进行分配。</p><h2 id="_1、malloc-函数" tabindex="-1"><a class="header-anchor" href="#_1、malloc-函数"><span>1、malloc 函数</span></a></h2><p>函数原型: void* malloc(unsigned int size);</p><h4 id="功能说明" tabindex="-1"><a class="header-anchor" href="#功能说明"><span>功能说明</span></a></h4><p>在内存的动态存储区(堆区)中分配一块长度为 size 字节的连续区域，用来存放类型说明符指定的类型函数原型返回 void* 指针，使用时必须做相应的强制类型转换，分配的内存空间内容不确定，一般使用memset 初始化。</p><h5 id="返回值" tabindex="-1"><a class="header-anchor" href="#返回值"><span>返回值</span></a></h5><p>分配空间的起始地址 (分配成功) NULL (分配失败)</p><p>在调用 malloc之后，一定要判断一下，是否申请内存成功。 如果多次 malloc 申请的内存，第 1 次和第 2 次请的内存不一定是连续的 要导入stdlib.h库</p><h2 id="_2、free-函数-释内存函数" tabindex="-1"><a class="header-anchor" href="#_2、free-函数-释内存函数"><span>2、free 函数(释内存函数)</span></a></h2><p>要导入stdlib.h库</p><p>函数定义:void free(void * ptr) 函数说明: free 函数释放 ptr 指向的内存。 注意 ptr指向的内存必须是malloc、calloc、relloc动态申请的内存</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char *p=(char *)malloc(100);</span></span>
<span class="line"><span>free(p);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>free 后，因为没有给 p 赋值，所以 p 还是指向原先动态申请的内存。但是内存已经不能再用了,p 变成野指针了。 一块动态申请的内存只能 free 一次，不能多次 free</p><h2 id="_3、calloc函数" tabindex="-1"><a class="header-anchor" href="#_3、calloc函数"><span>3、calloc函数</span></a></h2><p>要导入stdlib.h库</p><p>函数定义: void* calloc(size_t nmemb,size t size);</p><p>size_t 实际是无符号整型，它是在头文件中，用 typedef 定义出来的。</p><p>函数的功能:在内存的堆中，申请nmemb 块，每块的大小为 size 个字节的连续区域函数的返回值: 返回申请的内存的首地址 (申请成功) 返回NULL (申请失败)</p><h5 id="malloc和-calloc函数都是用来申请内存的。区别" tabindex="-1"><a class="header-anchor" href="#malloc和-calloc函数都是用来申请内存的。区别"><span>malloc和 calloc函数都是用来申请内存的。区别:</span></a></h5><p>参数的个数不一样 malloc 申请的内存，内存中存放的内容是随机的，不确定的，而 calloc 函数申请的内存中的内容为0</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char *p=(char *)calloc(3100);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在堆中申请了3块，每块大小为 100 个字节，即300 个字节连续的区域</p><h2 id="_4、realloc函数-重新申请内存" tabindex="-1"><a class="header-anchor" href="#_4、realloc函数-重新申请内存"><span>4、realloc函数(重新申请内存)</span></a></h2><p>调用 malloc和 calloc 函数单次申请的内存是连续的，两次申请的两块内存不一定连续。有些时候有这种需求，即先用 malloc 或者 calloc 申请了一块内存，我还想在原先内存的基础上挨着申请内存。或者开始时候使用 malloc 或 calloc 申请了一块内存，想释放后边的一部分内存。为了解决这个问题，发明了 realloc 这个函数</p><p>找一个 newsize 个字节大小的内存申请，将原先内存中的内容拷贝过来，然后释放原先的内存，最后返回新内存的地址。</p><p>如果newsize 比原先的内存小，则会释放原先内存的后面的存储空间，只留前面的 newsize个字节 返回值:新申请的内存的首地址</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char *p;</span></span>
<span class="line"><span>p=(char *)malloc(100);</span></span>
<span class="line"><span>p=(char *)realloc(p,150);//p 指向的内存的新的大小为 150 个字节</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>![[Pasted image 20230918210649.png]]</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char*p;</span></span>
<span class="line"><span>p=(char *)malloc(100);</span></span>
<span class="line"><span>//们想重新申请内存,新的大小为 50 个字节</span></span>
<span class="line"><span>5=(char *)realloc(p,50);//p 指向的内存的新的大小为 50 个字节,100 个字节的后50 个字节的存储空间就被释放了</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>malloc、calloc、relloc 动态申请的内存，只有在 free 或程序结束的时候才释放</p><h2 id="内存泄露" tabindex="-1"><a class="header-anchor" href="#内存泄露"><span>内存泄露</span></a></h2><h3 id="概念" tabindex="-1"><a class="header-anchor" href="#概念"><span>概念</span></a></h3><p>申请的内存，首地址丢了，找不了，再也没法使用了，也没法释放了，这块内存就被泄露了。 例：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int main()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	char*p;</span></span>
<span class="line"><span>	p=(char*)malloc(100);</span></span>
<span class="line"><span>	//接下来，可以用 p 指向的内存了</span></span>
<span class="line"><span>	p=&quot;hello world”;//p 指向别的地方了</span></span>
<span class="line"><span>	//从此以后，再也找不到你申请的 100 个字节了。则动态申请的 100 个字节就被泄露了</span></span>
<span class="line"><span>	return 0;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>解决方法1：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void fun()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	char*p;</span></span>
<span class="line"><span>	p=(char*)malloc(100);</span></span>
<span class="line"><span>	//接下来，可以用 p 指向的内存了</span></span>
<span class="line"><span>	free(p);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>int main()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	fun0;</span></span>
<span class="line"><span>	fun0);</span></span>
<span class="line"><span>	return 0;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>解决方法2</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void *fun()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	char*p;</span></span>
<span class="line"><span>	p=(char*)malloc(100);</span></span>
<span class="line"><span>	//接下来，可以用 p 指向的内存了</span></span>
<span class="line"><span>	free(p);</span></span>
<span class="line"><span>	return p;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>int main()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	char *q;</span></span>
<span class="line"><span>	q=fun();</span></span>
<span class="line"><span>	//可以通过 q 使用，动态申请的 100 个字节的内存了</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	//记得释放</span></span>
<span class="line"><span>	free(q);</span></span>
<span class="line"><span>	return 0;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div>`,112)]))}const h=s(l,[["render",p]]),r=JSON.parse('{"path":"/cpp/c/1/","title":"1 编译过程","lang":"zh-CN","frontmatter":{"title":"1 编译过程","createTime":"2025/04/05 12:12:26","permalink":"/cpp/c/1/"},"readingTime":{"minutes":8.09,"words":2428},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/C/1 编译过程.md","headers":[]}');export{h as comp,r as data};
